	public LobbyGui()
	{
		_0021XamlIlPopulateTrampoline(this);
		IoCManager.InjectDependencies<LobbyGui>(this);
		LayoutContainer.SetAnchorPreset((Control)(object)MainContainer, (LayoutPreset)15, false);
		LayoutContainer.SetAnchorPreset((Control)(object)Background, (LayoutPreset)15, false);
		LayoutContainer.SetAnchorPreset((Control)(object)ParallaxControl, (LayoutPreset)15, false);
		LayoutContainer.SetAnchorPreset((Control)(object)LobbyToastContainer, (LayoutPreset)3, false);
		LayoutContainer.SetGrowHorizontal((Control)(object)LobbyToastContainer, (GrowDirection)1);
		LayoutContainer.SetGrowVertical((Control)(object)LobbyToastContainer, (GrowDirection)1);
		LayoutContainer.SetMarginRight((Control)(object)LobbyToastContainer, -58f);
		LayoutContainer.SetMarginBottom((Control)(object)LobbyToastContainer, -298f);
		((BaseButton)LeaveButton).OnPressed += delegate
		{
			((IConsoleHost)_consoleHost).ExecuteCommand("disconnect");
		};
		((BaseButton)OptionsButton).OnPressed += delegate
		{
			((Control)this).UserInterfaceManager.GetUIController<OptionsUIController>().ToggleWindow();
		};
		((BaseButton)Discord).OnPressed += delegate
		{
			_uriOpener.OpenUri(new Uri("https://discord.gg/ds14"));
		};
		((BaseButton)Rules).OnPressed += delegate
		{
			((BaseWindow)new RulesAndInfoWindow()).Open();
		};
		((BaseButton)Changelog).OnPressed += delegate
		{
			((Control)this).UserInterfaceManager.GetUIController<ChangelogUIController>().ToggleWindow();
		};
		((BaseButton)Leaderboard).OnPressed += delegate
		{
			ToggleLeaderboard();
		};
		((BaseButton)ShowGUI).OnPressed += delegate
		{
			ToggleLobbyVisibility();
		};
	}

	public void SwitchState(LobbyGuiState state)
	{
		switch (state)
		{
		case LobbyGuiState.Default:
			CharacterSetupState.Visible = false;
			((Control)SplitContainer).Visible = true;
			break;
		case LobbyGuiState.CharacterSetup:
			CharacterSetupState.Visible = true;
			((Control)SplitContainer).Visible = false;
			((Control)this).UserInterfaceManager.GetUIController<LobbyUIController>().ReloadCharacterSetup();
			break;
		}
	}

	private void ToggleLobbyVisibility()
	{
		((BaseButton)ShowGUI).Pressed = !((BaseButton)ShowGUI).Pressed;
		((Control)CenterPanel).Visible = !((BaseButton)ShowGUI).Pressed;
		((Control)BottomContainer).Visible = !((BaseButton)ShowGUI).Pressed;
	}

	private void ToggleLeaderboard()
	{
		if (_leaderboardWindow == null)
		{
			_leaderboardWindow = new LeaderboardWindow();
			((BaseWindow)_leaderboardWindow).OnClose += delegate
			{
